class Solution:
    def solve(self, s1: str, s2: str) -> int:
        n = len(s1);
m = len(s2);

        # Implement dynamic programming
        dp = [[0] * (m + 1) for _ in range(n + 1)];
        for i in range(n + 1):
            dp[i][0] = i;
        for j in range(m + 1):
            dp[0][j] = j;
        for i in range(1, n + 1):
            for j in range(1, m + 1):
                if s1[i - 1] == s2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1];
                else:
                    dp[i][j] = 1 + min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
        return dp[n][m];

