class Solution {
public:
int solve(const std::string& s1, const std::string& s2) {
    int n = s1.size();
    int m = s2.size();

    // Implement dynamic programming
    std::vector<std::vector<int>> dp(n + 1, std::vector<int>(m + 1));
    for (int i = 0; i <= n; i++)
        dp[i][0] = i;
    for (int j = 0; j <= m; j++)
        dp[0][j] = j;
    for (int i = 1; i <= n; i++)
        for (int j = 1; j <= m; j++)
            if (s1[i - 1] == s2[j - 1])
                dp[i][j] = dp[i - 1][j - 1];
            else
                dp[i][j] = 1 + std::min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    return dp[n][m];
}
};
